import React from 'react';
import { motion } from 'framer-motion';
import DotMatrixIcon from './DotMatrixIcon';

interface Agent {
    id: string;
    name: string;
    status: 'READY' | 'SYNCING' | 'ALERT';
    type: string;
}

const agents: Agent[] = [
    { id: '1', name: 'AGENT_VISION', status: 'READY', type: 'COGNITIVE' },
    { id: '2', name: 'AGENT_READINESS', status: 'READY', type: 'ACTUARIAL' },
    { id: '3', name: 'AGENT_COST', status: 'SYNCING', type: 'OPTIMIZER' },
    { id: '4', name: 'AGENT_QUERY', status: 'ALERT', type: 'ROUTING' },
];

export const AgentRegistry: React.FC = () => {
    return (
        <div className="space-y-4">
            {agents.map((agent, i) => (
                <motion.div
                    key={agent.id}
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: i * 0.1 }}
                    className="flex items-center justify-between p-3 rounded-xl hover:bg-white/[0.02] transition-colors border border-transparent hover:border-white/5 group"
                >
                    <div className="flex items-center space-x-4">
                        <DotMatrixIcon
                            type={agent.status === 'ALERT' ? 'alert' : 'clear'}
                            size={24}
                            color={agent.status === 'ALERT' ? '#FF3B30' : '#FFFFFF'}
                            animate={agent.status === 'SYNCING'}
                        />
                        <div className="flex flex-col">
                            <span className="text-[12px] font-black tracking-tighter text-white group-hover:text-white transition-colors">
                                {agent.name}
                            </span>
                            <span className="text-[8px] text-white/30 tracking-[0.2em] font-mono">
                                {agent.type}
                            </span>
                        </div>
                    </div>

                    <div className="flex items-center space-x-3 text-right">
                        <span className={`text-[9px] font-bold tracking-widest ${agent.status === 'ALERT' ? 'text-[#FF3B30]' :
                                agent.status === 'SYNCING' ? 'text-white/60' : 'text-white/40'
                            }`}>
                            {agent.status}
                        </span>
                        <div className={`w-1 h-1 rounded-full ${agent.status === 'ALERT' ? 'bg-[#FF3B30] animate-pulse' :
                                agent.status === 'SYNCING' ? 'bg-white/40' : 'bg-white/10'
                            }`} />
                    </div>
                </motion.div>
            ))}

            <div className="pt-4 mt-4 border-t border-white/5 opacity-50">
                <div className="flex justify-between items-center text-[8px] text-white/40 font-mono tracking-widest">
                    <span>REGISTRY_POLLING: 200MS</span>
                    <span>ENTRIES: {agents.length}</span>
                </div>
            </div>
        </div>
    );
};
